return items.map((item, index) => {
  // Get the URL and title from the input
  const url = item.json.url;
  const title = item.json.title || null;
  // Extract the video ID from the URL
  let videoId = null;

  if (url && url.includes('v=')) {
    videoId = url.split('v=')[1].split('&')[0];
  }
  // id starts from 1; change to index+2 if you want to start from 2
  return {
    json: {
      id: index + 2,
      videoId,
      title
    }
  };
});

// Extract video URLs, titles, and add an id starting from 2
return items.map((item, index) => {
  const videoId = item.json.id.videoId;
  const title = item.json.snippet.title
  return {
    json: {
      id: index + 2,
      url: `https://www.youtube.com/watch?v=${videoId}`,
      title: title
    }
  };
});

const videoData = $('GET VIDEO DATA').first().json;
const videoId = videoData.id.videoId;
const thumbnailUrl = videoData.snippet.thumbnails.high.url;

return [{
  json: {
    videoId: videoId,
    thumbnailUrl: thumbnailUrl,
    videoUrl: `https://www.youtube.com/watch?v=${videoId}`
  }
}];

// Combine all "text" fields from the content array into one string
let script = "";
for (const item of items) {
    const content = item.json?.content;

    if (Array.isArray(content)) {
        for (const segment of content) {
            if (typeof segment?.text === "string") {
                script += segment?.text + " ";
            }
        }
    }
}

script = script.trim();

return [
    {
        json: { script },
    },
];
